const items = $input.all();

// Reliable source for is_voice and chat_id regardless of AI Agent output shape
const normalizeJson = $('Normalize Input').first().json;
const isVoice = !!normalizeJson.is_voice;
const chatId = normalizeJson.chat_id;

function sanitizeForTelegram(text) {
  // Replace Markdown/HTML trigger characters with visually similar full-width chars
  const map = {
    "*": "＊", "_": "＿", "`": "｀",
    "[": "［", "]": "］",
    "(": "（", ")": "）",
    "<": "‹", ">": "›",
    "&": "＆",
  };
  return String(text ?? "")
    .replace(/[\u200B-\u200D\uFEFF]/g, "")
    .replace(/\\([_*[\]()~`>#+\-=|{}.!\\])/g, "$1")
    .replace(/[*_`[\]()<>&]/g, (ch) => map[ch] ?? ch)
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function stripMediaTag(text) {
  return String(text ?? "").replace(/\[MEDIA:[^\]]*\]/g, "").trim();
}

function chunkText(text, maxLen = 3800) {
  const s = String(text ?? "");
  if (s.length <= maxLen) return [s];
  const parts = [];
  let i = 0;
  while (i < s.length) {
    let end = Math.min(i + maxLen, s.length);
    const slice = s.slice(i, end);
    const lastNL = slice.lastIndexOf("\n");
    if (lastNL > 800) end = i + lastNL;
    else {
      const lastSpace = slice.lastIndexOf(" ");
      if (lastSpace > 800) end = i + lastSpace;
    }
    parts.push(s.slice(i, end).trim());
    i = end;
  }
  return parts.filter(Boolean);
}

const out = [];
const HEADER = "Cortana — Aircraft Maintenance Intelligence";
const FALLBACK = "Cortana ready. Please provide the aircraft type, system, ATA chapter, and fault or task description.";

for (const item of items) {
  const root = item.json ?? {};
  const payload = root.output && typeof root.output === "object" ? root.output : root;

  // Raw AI output (may include "Cortana — Aircraft Maintenance Intelligence\n\n..." prefix)
  let rawOutput = (payload.state ?? payload.response ?? payload.output ?? "").toString().trim() || FALLBACK;

  // clean_text: strip header + MEDIA tag — fed to TTS (no char sanitization for natural speech)
  let cleanOutput = rawOutput
    .replace(/^Cortana\s*—\s*Aircraft Maintenance Intelligence\s*/i, "")
    .trim();
  cleanOutput = stripMediaTag(cleanOutput);

  // telegram_text: full formatted text with Cortana header
  const hasHeader = rawOutput.match(/^Cortana\s*—\s*Aircraft Maintenance Intelligence/i);
  let fullText = hasHeader
    ? rawOutput                              // AI already added it — use as-is
    : `${HEADER}\n\n${rawOutput}`;           // AI skipped it — add it

  fullText = sanitizeForTelegram(fullText);

  const hasMedia = rawOutput.includes("[MEDIA:");

  const parts = chunkText(fullText, 3800);
  const total = parts.length;

  parts.forEach((part, idx) => {
    out.push({
      json: {
        telegram_text: total > 1 ? `(${idx + 1}/${total})\n\n${part}` : part,
        clean_text: idx === 0 ? cleanOutput : "",  // TTS only needs first chunk
        is_voice: isVoice,
        chat_id: chatId,
        has_media: hasMedia && idx === 0,
      },
    });
  });
}

return out;

const item = $input.first();
const rawText = item.json.telegram_text || item.json.output || '';

// Parse [MEDIA:{file_id}:{mime_type}] tag
const mediaMatch = rawText.match(/\[MEDIA:([^:\]]+):([^\]]+)\]/);
if (!mediaMatch) throw new Error('No [MEDIA:] tag found in response text');

const fileId = mediaMatch[1].trim();
const mimeType = mediaMatch[2].trim();

// Strip the tag from text (keep clean response for user)
const cleanText = rawText.replace(/\s*\[MEDIA:[^\]]+\]\s*/g, '').trim();

const chatId = $('Normalize Input').first().json.chat_id;

return [{
  json: {
    file_id: fileId,
    mime_type: mimeType,
    clean_text: cleanText,
    chat_id: chatId,
    is_image: mimeType.startsWith('image/'),
    is_video: mimeType.startsWith('video/'),
  }
}];

const item = $input.first();
const binaryData = item.binary?.data;
// base64 string length × 0.75 ≈ actual byte count
const sizeBytes = binaryData ? Math.round(binaryData.data.length * 0.75) : 0;

return [{
  json: { ...item.json, file_size_bytes: sizeBytes },
  binary: item.binary
}];

const item = $input.first();
const transcribed = (item.json.text || '').trim();
if (!transcribed) throw new Error('Whisper STT returned empty transcription');

const tokenNode = $('Read Bot Token').first().json;
return [{ json: {
  text: transcribed,
  chat_id: tokenNode.chat_id,
  is_voice: true,
  voice_mime_type: tokenNode.voice_mime_type,
} }];

const item = $input.first();
const responseText = item.json.clean_text || item.json.telegram_text || item.json.output || '';

const requestBody = {
  model: 'tts-1',
  input: responseText,
  voice: 'nova',
  response_format: 'mp3'
};

return [{ json: {
  requestBody,
  chat_id: item.json.chat_id,
  is_voice: item.json.is_voice,
  telegram_text: item.json.telegram_text,
  clean_text: item.json.clean_text,
  has_media: (item.json.telegram_text || item.json.output || '').includes('[MEDIA:')
} }];

const item = $input.first();

// OpenAI TTS returns binary MP3 directly — no PCM conversion needed
// Binary is stored by HTTP node in item.binary.data
return [{
  json: {
    chat_id: $('Prepare TTS Request').first().json.chat_id,
    is_voice: $('Prepare TTS Request').first().json.is_voice,
    clean_text: $('Prepare TTS Request').first().json.clean_text,
    telegram_text: $('Prepare TTS Request').first().json.telegram_text,
    has_media: $('Prepare TTS Request').first().json.has_media,
  },
  binary: item.binary
}];

const item = $input.first();
const text = (item.json.text || '').trim();
const fromId = item.json.from_id || 0;
const chatId = item.json.chat_id;
const staticData = $getWorkflowStaticData('global');
const OWNER_ID = __TELEGRAM_CHAT_ID__;

// Only owner can run admin commands
if (fromId !== OWNER_ID) {
  return [{ json: { chat_id: chatId, reply: '⛔ Only the owner can run admin commands.' } }];
}

let reply = '';

if (/^\/settoken\s+/i.test(text)) {
  const token = text.replace(/^\/settoken\s+/i, '').trim();
  if (!token || !token.match(/^\d+:[A-Za-z0-9_-]+$/)) {
    reply = '❌ Invalid token format. Expected: 123456789:ABCdef...';
  } else {
    staticData.telegram_bot_token = token;
    reply = '✅ Bot token saved. Voice transcription is now active.';
  }

} else if (/^\/adduser\s+/i.test(text)) {
  const userId = parseInt(text.replace(/^\/adduser\s+/i, '').trim());
  if (!userId || isNaN(userId)) {
    reply = '❌ Usage: /adduser 123456789';
  } else {
    const list = Array.isArray(staticData.authorized_users) ? staticData.authorized_users : [];
    if (!list.includes(userId)) list.push(userId);
    staticData.authorized_users = list;
    reply = `✅ User ${userId} added to whitelist. Total authorized: ${list.length + 1} (owner + ${list.length})`;
  }

} else if (/^\/removeuser\s+/i.test(text)) {
  const userId = parseInt(text.replace(/^\/removeuser\s+/i, '').trim());
  if (!userId || isNaN(userId)) {
    reply = '❌ Usage: /removeuser 123456789';
  } else {
    const list = Array.isArray(staticData.authorized_users) ? staticData.authorized_users : [];
    staticData.authorized_users = list.filter(id => id !== userId);
    reply = `✅ User ${userId} removed from whitelist.`;
  }

} else if (/^\/setwebhookkey\s+/i.test(text)) {
  const key = text.replace(/^\/setwebhookkey\s+/i, '').trim();
  if (key.length < 16) {
    reply = '❌ Key too short. Use at least 16 characters.';
  } else {
    staticData.webhook_api_key = key;
    reply = '✅ Webhook API key saved. Include X-Api-Key header in all webhook requests.';
  }

} else if (text === '/listusers') {
  const list = Array.isArray(staticData.authorized_users) ? staticData.authorized_users : [];
  reply = `👥 Authorized users:\n• ${OWNER_ID} (owner)\n${list.map(id => '• ' + id).join('\n') || '(none)'}`;

} else {
  reply = '❓ Unknown command. Available: /settoken, /adduser, /removeuser, /setwebhookkey, /listusers';
}

return [{ json: { chat_id: chatId, reply } }];

const staticData = $getWorkflowStaticData('global');
const botToken = staticData.telegram_bot_token;
if (!botToken) {
  throw new Error('Bot token not set. Send /settoken YOUR_BOT_TOKEN to the bot first.');
}

const item = $input.first();
const fileId = $('Telegram Trigger').first().json.message?.voice?.file_id;
if (!fileId) throw new Error('No voice file_id found in Telegram message');

return [{ json: {
  bot_token: botToken,
  file_id: fileId,
  chat_id: item.json.chat_id,
  is_voice: true,
  voice_mime_type: item.json.voice_mime_type || 'audio/ogg',
} }];

const fileInfo = $input.first().json;
const fileUri = fileInfo.file && fileInfo.file.uri;
if (!fileUri) {
  throw new Error('No file URI from Gemini Files upload: ' + JSON.stringify(fileInfo));
}

const tokenNode = $('Read Bot Token').first().json;
const voiceMime = tokenNode.voice_mime_type || 'audio/ogg';

const requestBody = {
  contents: [{
    parts: [
      { file_data: { mime_type: voiceMime, file_uri: fileUri } },
      { text: 'Transcribe this audio accurately. Return ONLY the transcription, nothing else.' }
    ]
  }],
  generationConfig: { temperature: 0 },
};

return [{ json: {
  requestBody,
  chat_id: tokenNode.chat_id,
  is_voice: true,
  voice_mime_type: voiceMime,
} }];

const item = $input.first();
const json = item.json;
const fromId = json.from_id || 0;
const staticData = $getWorkflowStaticData('global');
const OWNER_ID = __TELEGRAM_CHAT_ID__;
const whitelist = Array.isArray(staticData.authorized_users) ? staticData.authorized_users : [];

let authorized = false;
if (fromId > 0) {
  authorized = (fromId === OWNER_ID) || whitelist.includes(fromId);
} else {
  const storedKey = staticData.webhook_api_key || '';
  authorized = storedKey.length === 0 ? true : (() => {
    const headers = json.headers || {};
    const provided = headers['x-api-key'] || headers['X-Api-Key'] || '';
    return provided === storedKey;
  })();
}

return [{ json: { ...json, authorized } }];

const staticData = $getWorkflowStaticData('global');
const botToken = staticData.telegram_bot_token;
if (!botToken) throw new Error('Bot token not set. Send /settoken YOUR_BOT_TOKEN first.');
const item = $input.first();
return [{ json: {
  bot_token: botToken,
  photo_file_id: item.json.photo_file_id,
  chat_id: item.json.chat_id,
  caption: item.json.caption || '',
  is_voice: false
}}];

const item = $input.first();
// Direct Telegram file URL — publicly accessible HTTPS, no external hosting needed
const imageUrl = item.json.image_url;
const caption = item.json.caption || '';
const chat_id = item.json.chat_id;

const userText = caption || 'Analyze this aviation maintenance image. Identify any visible text, part numbers, serial numbers, fault codes, and components. Provide relevant maintenance guidance with ATA chapter references if applicable.';

const messages = [
  { role: 'system', content: 'You are Cortana, an AI aviation maintenance assistant. You help technicians interpret maintenance photos, wiring diagrams, damage assessments, component images, and fault code screenshots. Extract all visible text and part numbers. Provide precise, ATA-referenced guidance.' },
  { role: 'user', content: [
    { type: 'image_url', image_url: { url: imageUrl } },
    { type: 'text', text: userText }
  ]}
];

return [{ json: {
  requestBody: { model: 'gpt-4o', messages, max_tokens: 1000 },
  chat_id,
  image_url: imageUrl
}}];

const item = $input.first();
const response = item.json;
const visionAnalysis = response.choices?.[0]?.message?.content || '';

// Support both Telegram path (Build Vision Request) and dashboard path (Build Dashboard Vision Request)
let visionData, caption;
try {
  visionData = $('Build Vision Request').first().json;
  caption = $('Get Photo Token').first().json.caption || '';
} catch (e) {
  visionData = $('Build Dashboard Vision Request').first().json;
  caption = '';  // Dashboard path: user text is already in chatInput
}

const captionLine = caption ? `\nUser question: ${caption}` : '';
const text = `[Image Analysis]\n${visionAnalysis}${captionLine}\n\nSearch the knowledge base for any part numbers, fault codes, ATA references, or components identified above and provide relevant maintenance guidance.`;

return [{ json: {
  text,
  chat_id: visionData.chat_id,
  is_voice: false,
  is_photo: true
}}];

const item = $input.first();
const text = item.json.text || '';
const cleanText = text.startsWith('/cortana ')
  ? text.slice(9).trim()
  : text === '/cortana' ? '' : text;
return [{ json: { ...item.json, text: cleanText } }];

const imageUrl = $json.image_url;
const userText = $json.text || 'Analyse this image for aviation maintenance context.';
return [{
  json: {
    requestBody: {
      model: 'gpt-4o',
      messages: [{
        role: 'user',
        content: [
          { type: 'text', text: userText },
          { type: 'image_url', image_url: { url: imageUrl, detail: 'high' } }
        ]
      }],
      max_tokens: 1000
    },
    chat_id: $json.chat_id
  }
}];

const clean = $json.pdf_content
  .replace(/\r/g, ' ').replace(/\t/g, ' ')
  .replace(/[\u201C\u201D]/g, "'").replace(/[\u2018\u2019]/g, "'")
  .trim();
const combined = '[Document: ' + $json.file_name + ']\n\n' + clean + '\n\n---\nUser question: ' + ($json.text || 'Analyse this document.');
return [{ json: { ...$json, text: combined } }];

const botToken = $('Get Photo Token').first().json.bot_token;
const filePath = $input.first().json.result.file_path;
const chat_id = $('Get Photo Token').first().json.chat_id;
const caption = $('Get Photo Token').first().json.caption || '';

return [{ json: {
  image_url: `https://api.telegram.org/file/bot${botToken}/${filePath}`,
  chat_id,
  caption
}}];
